import { describe, expect, it, vi } from 'vitest';
import { executeGraphViewAnalysis } from '../../../../src/extension/graphView/analysis/execution';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './execution/fixtures';

describe('graph view analysis execution', () => {
  it('logs non-abort analysis failures and publishes an empty graph fallback', async () => {
    const error = new Error('boom');
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        analyze: vi.fn(async () => {
          throw error;
        }),
      }),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    await executeGraphViewAnalysis(new AbortController().signal, 1, state, handlers);

    expect(handlers.logError).toHaveBeenCalledWith('[CodeGraphy] Analysis failed:', error);
    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.setGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('returns quietly for abort errors raised during analysis', async () => {
    const error = Object.assign(new Error('aborted'), { name: 'AbortError' });
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        analyze: vi.fn(async () => {
          throw error;
        }),
      }),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers({
      isAbortError: vi.fn(nextError => nextError === error),
    });

    await executeGraphViewAnalysis(new AbortController().signal, 1, state, handlers);

    expect(handlers.logError).not.toHaveBeenCalled();
    expect(handlers.setRawGraphData).not.toHaveBeenCalled();
    expect(handlers.sendPluginStatuses).not.toHaveBeenCalled();
    expect(handlers.markWorkspaceReady).not.toHaveBeenCalled();
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  refreshGraphViewRawData,
  refreshIncrementalGraphViewRawData,
} from '../../../../../src/extension/graphView/analysis/execution/refresh';
import {
  createExecutionAnalyzer,
  createExecutionState,
} from './fixtures';
import { EMPTY_GRAPH_DATA } from '../../../../../src/extension/graphView/analysis/execution/publish';

describe('graph view analysis execution refresh', () => {
  it('runs explicit full refresh through the analyzer refresh path', async () => {
    const refreshIndex = vi.fn(async () => ({ nodes: [], edges: [] }));
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex,
      }),
      analyzerInitialized: true,
    });

    await refreshGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshIndex).toHaveBeenCalledOnce();
    expect(analyze).not.toHaveBeenCalled();
  });

  it('falls back to analyzer analyze for full refreshes when refreshIndex is unavailable', async () => {
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual({ nodes: [], edges: [] });
    expect(analyze).toHaveBeenCalledOnce();
  });

  it('runs scoped incremental refresh through the changed-file analyzer path', async () => {
    const refreshChangedFiles = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: ['src/index.ts'],
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshChangedFiles).toHaveBeenCalledWith(
      ['src/index.ts'],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to analyzer analyze when incremental refresh support is unavailable', async () => {
    const analyzeResult = { nodes: [], edges: [] };
    const analyze = vi.fn(async () => analyzeResult);
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshChangedFiles: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(analyzeResult);

    expect(analyze).toHaveBeenCalledOnce();
  });

  it('uses empty changed-file paths for incremental refreshes and falls back to the empty graph', async () => {
    const refreshChangedFiles = vi.fn(async () => undefined as never);
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: undefined,
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(EMPTY_GRAPH_DATA);
    expect(refreshChangedFiles).toHaveBeenCalledWith(
      [],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to the empty graph when no refresh or analyze path is available', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze: undefined,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for a full refresh', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for an incremental refresh', async () => {
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import {
  publishAnalyzedGraph,
  publishAnalysisFailure,
  publishEmptyGraph,
} from '../../../../../src/extension/graphView/analysis/execution/publish';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution publish', () => {
  it('publishes an empty graph and index state', () => {
    const { handlers } = createExecutionHandlers();

    const graphData = publishEmptyGraph(handlers, true);

    expect(graphData).toEqual({ nodes: [], edges: [] });
    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.setGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(true);
    expect(handlers.sendDepthState).toHaveBeenCalledOnce();
  });

  it('defaults empty graph publication to a missing index', () => {
    const { handlers } = createExecutionHandlers();

    publishEmptyGraph(handlers);

    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(false);
  });

  it('publishes the transformed graph and notifies post-analyze hooks', () => {
    const rawGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const transformedGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        analyze: vi.fn(() => Promise.resolve(rawGraphData)),
      }),
    });
    const { handlers, getGraphData } = createExecutionHandlers({
      applyViewTransform: vi.fn(() => {
        handlers.setGraphData(transformedGraphData);
      }),
    });

    publishAnalyzedGraph(state, handlers, rawGraphData, true);

    expect(handlers.updateViewContext).toHaveBeenCalledOnce();
    expect(handlers.applyViewTransform).toHaveBeenCalledOnce();
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith(transformedGraphData);
    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.sendDecorations).toHaveBeenCalledOnce();
    expect(handlers.sendContextMenuItems).toHaveBeenCalledOnce();
    expect(state.analyzer?.registry.notifyPostAnalyze).toHaveBeenCalledWith(getGraphData());
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith(getGraphData());
  });

  it('publishes the transformed graph without post-analyze hooks when no analyzer is available', () => {
    const rawGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const state = createExecutionState();
    const { handlers, getGraphData } = createExecutionHandlers();

    expect(() => publishAnalyzedGraph(state, handlers, rawGraphData, false)).not.toThrow();

    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(false);
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith(getGraphData());
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith(getGraphData());
  });

  it('publishes an empty graph fallback with plugin state updates after failures', () => {
    const { handlers } = createExecutionHandlers({
      sendPluginExporters: vi.fn(),
      sendPluginToolbarActions: vi.fn(),
    });

    publishAnalysisFailure(handlers);

    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.sendPluginExporters).toHaveBeenCalledOnce();
    expect(handlers.sendPluginToolbarActions).toHaveBeenCalledOnce();
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('publishes an empty graph fallback when optional plugin broadcasts are absent', () => {
    const { handlers } = createExecutionHandlers();

    expect(() => publishAnalysisFailure(handlers)).not.toThrow();

    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });
});

import { describe, expect, it, vi } from 'vitest';
import { prepareGraphViewAnalysis } from '../../../../../src/extension/graphView/analysis/execution/prepare';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution prepare', () => {
  it('returns before doing any work when the request is already stale', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn(() => true),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.computeMergedGroups).not.toHaveBeenCalled();
    expect(handlers.setRawGraphData).not.toHaveBeenCalled();
  });

  it('publishes an empty graph when no analyzer exists', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers();

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.setGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('stops when the request turns stale after initialization', async () => {
    const initialize = vi.fn(async () => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
    });
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn()
        .mockReturnValueOnce(false)
        .mockReturnValueOnce(false)
        .mockReturnValueOnce(true),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(initialize).toHaveBeenCalledOnce();
    expect(handlers.computeMergedGroups).not.toHaveBeenCalled();
  });

  it('publishes an empty graph after group recompute when no workspace is available', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers({
      hasWorkspace: vi.fn(() => false),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.computeMergedGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('returns true after plugin activation, initialization, and group preparation succeed', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
      installedPluginActivationPromise: Promise.resolve(),
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(handlers.computeMergedGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../src/shared/graph/types';
import {
  executeGraphViewProviderAnalysis,
  isGraphViewAbortError,
  isGraphViewAnalysisStale,
  markGraphViewWorkspaceReady,
  runGraphViewProviderAnalysisRequest,
  type GraphViewProviderAnalysisHandlers,
  type GraphViewProviderAnalysisState,
} from '../../../../src/extension/graphView/analysis/lifecycle';

function createState(
  overrides: Partial<GraphViewProviderAnalysisState> = {},
): GraphViewProviderAnalysisState {
  return {
    analysisController: undefined,
    analysisRequestId: 0,
    analyzer: undefined,
    analyzerInitialized: false,
    analyzerInitPromise: undefined,
    mode: 'analyze',
    filterPatterns: [],
    disabledPlugins: new Set<string>(),
    ...overrides,
  };
}

function createAnalyzer(overrides: Partial<NonNullable<GraphViewProviderAnalysisState['analyzer']>> = {}) {
  return {
    initialize: vi.fn(async () => undefined),
    hasIndex: vi.fn(() => true),
    discoverGraph: vi.fn(async () => ({ nodes: [], edges: [] })),
    analyze: vi.fn(async () => ({ nodes: [], edges: [] })),
    registry: {
      notifyPostAnalyze: vi.fn(),
    },
    ...overrides,
  };
}

function createHandlers(
  overrides: Partial<GraphViewProviderAnalysisHandlers> = {},
): GraphViewProviderAnalysisHandlers {
  let graphData: IGraphData = { nodes: [], edges: [] };

  return {
    hasWorkspace: vi.fn(() => true),
    setRawGraphData: vi.fn(),
    setGraphData: vi.fn((nextGraphData: IGraphData) => {
      graphData = nextGraphData;
    }),
    getGraphData: vi.fn(() => graphData),
    sendGraphDataUpdated: vi.fn(),
    sendDepthState: vi.fn(),
    computeMergedGroups: vi.fn(),
    sendGroupsUpdated: vi.fn(),
    updateViewContext: vi.fn(),
    applyViewTransform: vi.fn(),
    sendPluginStatuses: vi.fn(),
    sendDecorations: vi.fn(),
    sendContextMenuItems: vi.fn(),
    sendGraphIndexStatusUpdated: vi.fn(),
    markWorkspaceReady: vi.fn(),
    isAnalysisStale: vi.fn(() => false),
    isAbortError: vi.fn(() => false),
    logError: vi.fn(),
    ...overrides,
  };
}

describe('graph view provider analysis lifecycle helper', () => {
  it('runs the provider request flow and clears the active controller afterward', async () => {
    const state = createState({
      analysisController: new AbortController(),
    });
    const handlers = createHandlers();
    const updateAnalysisController = vi.fn();
    const updateAnalysisRequestId = vi.fn();

    await runGraphViewProviderAnalysisRequest(state, {
      executeAnalysis: (signal, requestId) =>
        executeGraphViewProviderAnalysis(signal, requestId, state, handlers),
      isAbortError: error => isGraphViewAbortError(error),
      logError: handlers.logError,
      updateAnalysisController,
      updateAnalysisRequestId,
    });

    expect(state.analysisRequestId).toBe(1);
    expect(state.analysisController).toBeUndefined();
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendDepthState).toHaveBeenCalledOnce();
    expect(updateAnalysisController).toHaveBeenNthCalledWith(
      1,
      expect.any(AbortController),
    );
    expect(updateAnalysisController).toHaveBeenLastCalledWith(undefined);
    expect(updateAnalysisRequestId).toHaveBeenCalledWith(1);
  });

  it('updates request state even when optional request update callbacks are absent', async () => {
    const state = createState();
    const handlers = createHandlers();

    await expect(
      runGraphViewProviderAnalysisRequest(state, {
        executeAnalysis: (signal, requestId) =>
          executeGraphViewProviderAnalysis(signal, requestId, state, handlers),
        isAbortError: error => isGraphViewAbortError(error),
        logError: handlers.logError,
      }),
    ).resolves.toBeUndefined();

    expect(state.analysisRequestId).toBe(1);
    expect(state.analysisController).toBeUndefined();
  });

  it('syncs analyzer initialization state after execution', async () => {
    const rawGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const state = createState({
      analysisRequestId: 1,
      analyzer: createAnalyzer({
        analyze: vi.fn(() => Promise.resolve(rawGraphData)),
      }),
    });
    const handlers = createHandlers();

    await executeGraphViewProviderAnalysis(new AbortController().signal, 1, state, handlers);

    expect(state.analyzerInitialized).toBe(true);
    expect(state.analyzerInitPromise).toBeUndefined();
    expect(state.analyzer?.initialize).toHaveBeenCalledOnce();
    expect(state.analyzer?.analyze).toHaveBeenCalledOnce();
  });

  it('forwards stale and abort checks through the provider wrappers', async () => {
    const abortController = new AbortController();
    const abortError = new Error('cancelled');
    abortError.name = 'AbortError';
    const state = createState({
      analysisRequestId: 1,
      analyzer: createAnalyzer({
        analyze: vi.fn(() => Promise.reject(abortError)),
      }),
    });
    const handlers = createHandlers({
      isAnalysisStale: vi.fn(() => false),
      isAbortError: vi.fn(() => true),
    });

    await executeGraphViewProviderAnalysis(abortController.signal, 1, state, handlers);

    expect(handlers.isAnalysisStale).toHaveBeenCalledWith(abortController.signal, 1);
    expect(handlers.isAbortError).toHaveBeenCalledWith(expect.anything());
  });

  it('marks workspace ready once and resolves waiters', () => {
    const resolveFirstWorkspaceReady = vi.fn();
    const workspaceReadyState = {
      firstAnalysis: true,
      resolveFirstWorkspaceReady,
    };
    const registry = {
      notifyWorkspaceReady: vi.fn(),
    };
    const graphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };

    markGraphViewWorkspaceReady(workspaceReadyState, registry, graphData);
    markGraphViewWorkspaceReady(workspaceReadyState, registry, graphData);

    expect(workspaceReadyState.firstAnalysis).toBe(false);
    expect(workspaceReadyState.resolveFirstWorkspaceReady).toBeUndefined();
    expect(registry.notifyWorkspaceReady).toHaveBeenCalledTimes(1);
    expect(resolveFirstWorkspaceReady).toHaveBeenCalledTimes(1);
  });

  it('marks first analysis complete without requiring registry listeners', () => {
    const workspaceReadyState = {
      firstAnalysis: true,
      resolveFirstWorkspaceReady: undefined,
    };

    expect(() =>
      markGraphViewWorkspaceReady(workspaceReadyState, undefined, {
        nodes: [],
        edges: [],
      }),
    ).not.toThrow();
    expect(workspaceReadyState.firstAnalysis).toBe(false);
    expect(workspaceReadyState.resolveFirstWorkspaceReady).toBeUndefined();
  });

  it('detects stale requests and abort errors', () => {
    const abortError = new Error('cancelled');
    abortError.name = 'AbortError';

    expect(isGraphViewAnalysisStale(new AbortController().signal, 2, 1)).toBe(true);
    expect(isGraphViewAnalysisStale(new AbortController().signal, 1, 1)).toBe(false);
    expect(isGraphViewAbortError(abortError)).toBe(true);
    expect(isGraphViewAbortError(new Error('boom'))).toBe(false);
    expect(isGraphViewAbortError('AbortError')).toBe(false);
  });

  it('marks workspace ready without requiring a waiting promise', () => {
    const registry = {
      notifyWorkspaceReady: vi.fn(),
    };
    const workspaceReadyState = {
      firstAnalysis: true,
      resolveFirstWorkspaceReady: undefined,
    };

    markGraphViewWorkspaceReady(workspaceReadyState, registry, {
      nodes: [],
      edges: [],
    });

    expect(registry.notifyWorkspaceReady).toHaveBeenCalledOnce();
    expect(workspaceReadyState.firstAnalysis).toBe(false);
  });
});

